def find_numbers(start, end):
    results = []
    for num in range(start, end + 1):
        if num % 7 == 0:
            if num % 5 != 0:
                results.append(num)
    return results

# Example usage:
start_range = 1
end_range = 100
print(find_numbers(start_range, end_range))

