# Creating a multi-dimensional array
matrix = [[0 for j in range(5)] for i in range(5)]

# Filling the array with values based on conditions
for i in range(len(matrix)):
    for j in range(len(matrix[i])):
        if (i + j) % 2 == 0:
            matrix[i][j] = 1  # Assign 1 if the sum of indices is even
        else:
            matrix[i][j] = 2  # Assign 2 if the sum of indices is odd

