class CompressedDataStructure:
    def __init__(self):
        self.data = {}

    def insert(self, key, value):
        if key not in self.data:
            self.data[key] = value
            print(f'Inserted: {key} -> {value}')
        else:
            print(f'Key {key} already exists. Skipping insertion.')

    def search(self, key):
        if key in self.data:
            print(f'Found: {key} -> {self.data[key]}')
            return

