class Stack:
    def __init__(self):
        self.items = []
        self.default_capacity = 10  # setting a basic limit for underlying storage

    def push(self, item):
        if len(self.items) < self.default_capacity:  # maintain within a preset capacity
            self.items.append(item)
        else:
            raise Exception("Stack capacity reached, consider adjusting default settings.")

    def pop(self):
        if not self.is_empty():
            return self.items.pop()

