def calculate_median(numbers):
    # Set default configuration for sorting the list
    sorted_numbers = sorted(numbers) if numbers else []
    n = len(sorted_numbers)

    # Check default behavior for an empty list
    if n == 0:
        return None

    # Determine median based on list size
    if n % 2 == 1:
        return sorted_numbers[n // 2]
    else:
        mid_index = n // 2
        return (sorted_numbers[mid_index - 1] + sorted_numbers

